function attackWithTower(building) {
  const spec = BUILDING_TYPES[building.type];
  if (!spec || !spec.attackDamage) return;

  let closest = null;
  let bestDist = Infinity;

  for (const unit of game.units.values()) {
    if (unit.ownerId === building.ownerId) continue;
    const d = distance(building, unit);
    if (d <= spec.attackRange && d < bestDist) {
      closest = unit;
      bestDist = d;
    }
  }

  if (!closest) return;
  if (now() - building.lastAttackAt < spec.attackCooldownMs) return;

  building.lastAttackAt = now();
  applyDamage(closest.id, spec.attackDamage, building.id);
}

function gameTick() {
  const current = now();
  const dt = Math.min((current - game.lastTickAt) / 1000, 0.1);
  game.lastTickAt = current;

  const changedUnits = [];
  const changedBuildings = [];

  for (const unit of game.units.values()) {
    const beforeX = unit.x;
    const beforeY = unit.y;
    const beforeCommand = unit.command ? JSON.stringify(unit.command) : null;

    if (unit.command) {
      if (unit.command.type === 'move') {
        moveUnit(unit, dt);
      } else if (unit.command.type === 'attack') {
        attackWithUnit(unit);
        if (unit.command && unit.command.type === 'move') {
          moveUnit(unit, dt);
          if (unit.targetId) unit.command = { type: 'attack', targetId: unit.targetId };
        }
      }
    }

    const afterCommand = unit.command ? JSON.stringify(unit.command) : null;
    if (beforeX !== unit.x || beforeY !== unit.y || beforeCommand !== afterCommand) {
      changedUnits.push({
        id: unit.id,
        x: unit.x,
        y: unit.y,
        hp: unit.hp,
        command: unit.command,
        targetId: unit.targetId
      });
    }
  }

  for (const building of game.buildings.values()) {
    const spec = BUILDING_TYPES[building.type];
    if (spec && spec.attackDamage) {
      const prevAttackAt = building.lastAttackAt;
      attackWithTower(building);
      if (prevAttackAt !== building.lastAttackAt) {
        changedBuildings.push({
          id: building.id,
          hp: building.hp,
          lastAttackAt: building.lastAttackAt
        });
      }
    }
  }

  if (changedUnits.length || changedBuildings.length) {
    broadcast({
      type: 'stateUpdate',
      serverTime: current,
      units: changedUnits,
      buildings: changedBuildings
    });
  }
}

const server = http.createServer((req, res) => {
  if (req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, players: game.players.size }));
    return;
  }
  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('RTS WebSocket server');
});

const wss = new WebSocket.Server({ server });

wss.on('connection', (ws) => {
  let playerId = null;

  ws.on('message', (data) => {
    if (!playerId) {
      let hello;
      try {
        hello = JSON.parse(data.toString());
      } catch {
        ws.close();
        return;
      }

      if (!hello || hello.type !== 'join') {
        ws.close();
        return;
      }

      const player = createPlayer(hello.name, ws);
      playerId = player.id;

      safeSend(ws, {
        type: 'welcome',
        playerId: player.id,
        name: player.name,
        serverTime: now(),
        map: { width: MAP_WIDTH, height: MAP_HEIGHT }
      });

      safeSend(ws, getSnapshot());
      broadcast({
        type: 'playerJoined',
        player: {
          id: player.id,
          name: player.name,
          resources: player.resources
        }
      });
      return;
    }

    processMessage(playerId, data.toString());
  });

  ws.on('close', () => {
    removePlayerConnection(ws);
  });

  ws.on('error', () => {
    removePlayerConnection(ws);
  });
});

setInterval(gameTick, TICK_MS);

server.listen(PORT, () => {
  console.log(`RTS WebSocket server running on port ${PORT}`);
});